SELECT player_id, games_played
FROM player_seasons
WHERE season = '2018-2019';

SELECT MAX(points_per_game) AS max_points_per_game
FROM player_seasons
WHERE season = '2018-2019';

SELECT AVG(points_per_game) AS avg_points_per_game
FROM player_seasons
WHERE games_played > 70;

SELECT MAX(salary) AS highest_salary
FROM player_salaries
WHERE season = '2018-2019';

SELECT player_name
FROM players
ORDER BY player_name;

SELECT efficiency
FROM player_advanced_stats
WHERE player_season_id = 1;

SELECT wins
FROM team_ranks
WHERE team_id = 1 AND season = '2018-2019';
